import React, { useState, useEffect } from "react";
import { supabase } from "../supabase";

interface PostProps {
  post: {
    id: string;
    content: string;
    created_at: string;
    profiles: {
      name: string;
      university: string | null;
    } | null;
  };
}

const PostItem: React.FC<PostProps> = ({ post }) => {
  const [liked, setLiked] = useState(false); // Se o usuário já curtiu
  const [likesCount, setLikesCount] = useState(0); // Contador de likes

  // Busca o número total de likes e se o usuário já curtiu
  const fetchLikes = async () => {
    const { data: userData } = await supabase.auth.getUser();
    const userId = userData?.user?.id;

    // Contar likes
    const { count: totalLikes } = await supabase
      .from("likes")
      .select("id", { count: "exact", head: true })
      .eq("post_id", post.id);

    setLikesCount(totalLikes || 0);

    if (userId) {
      // Verifica se o usuário já curtiu
      const { data: likeData } = await supabase
        .from("likes")
        .select("id")
        .eq("post_id", post.id)
        .eq("user_id", userId)
        .single();

      setLiked(!!likeData);
    }
  };

  useEffect(() => {
    fetchLikes();
  }, [post.id]);

  // Atualiza o like no banco
  const handleLike = async () => {
    const { data: userData } = await supabase.auth.getUser();
    const userId = userData?.user?.id;
    if (!userId) return; // Usuário não logado

    if (liked) {
      // Se já curtiu -> remover like
      await supabase
        .from("likes")
        .delete()
        .eq("post_id", post.id)
        .eq("user_id", userId);
      setLiked(false);
      setLikesCount(prev => prev - 1);
    } else {
      // Se não curtiu -> adicionar like
      await supabase
        .from("likes")
        .insert([{ post_id: post.id, user_id: userId }]);
      setLiked(true);
      setLikesCount(prev => prev + 1);
    }
  };

  return (
    <div className="post-item">
      <div className="post-header">
        <span className="author-name">{post.profiles?.name}</span>
        {post.profiles?.university && (
          <span className="university-name" style={{ color: "gray", marginLeft: "8px" }}>
            {post.profiles.university}
          </span>
        )}
      </div>

      <div className="post-content">
        <p>{post.content}</p>
      </div>

      <div className="post-footer">
        <span className="post-date">{post.created_at}</span>

        <button
          className={`like-btn ${liked ? "liked" : ""}`}
          style={{ marginLeft: "12px" }}
          onClick={handleLike}
        >
          {liked ? "❤️" : "🤍"} {likesCount}
        </button>
      </div>
    </div>
  );
};

export default PostItem;
