import React, { useState, useEffect } from "react";
import { supabase } from "../supabase";
import PostItem from "../components/PostItem";
import "./feed.css";

export default function Feed() {
  const [posts, setPosts] = useState<any[]>([]);
  const [text, setText] = useState("");

  useEffect(() => {
    const fetchPosts = async () => {
      const { data, error } = await supabase
        .from("posts")
        .select(`
          id,
          content,
          created_at,
          profiles!posts_author_id_fkey (id, name, university)
        `)
        .order("created_at", { ascending: false });

      if (error) {
        console.error("Erro ao carregar posts:", error);
      } else {
        setPosts(data || []); // Garante que estamos passando um array, nunca null
      }
    };

    fetchPosts();
  }, []);

  const handlePublish = async () => {
    if (!text.trim()) return;

    const {
      data: { user },
    } = await supabase.auth.getUser();

    if (!user) return;

    const { error } = await supabase.from("posts").insert({
      content: text,
      author_id: user.id,
    });

    if (!error) {
      setText("");
      const { data } = await supabase
        .from("posts")
        .select(`
          id,
          content,
          created_at,
          profiles!posts_author_id_fkey (id, name, university)
        `)
        .order("created_at", { ascending: false });
      setPosts(data || []); // Garante que estamos passando um array, nunca null
    }
  };

  return (
    <div className="feed-container">
      <header className="feed-header">
        <h1 className="logo">VibeU</h1>
      </header>

      <div className="publish-box">
        <textarea
          placeholder="Escreva algo..."
          value={text}
          onChange={(e) => setText(e.target.value)}
        />
        <button onClick={handlePublish}>Publicar</button>
      </div>

      <main>
        {posts.length === 0 ? (
          <p className="empty">Nenhum post ainda...</p>
        ) : (
          posts.map((post: any) => <PostItem key={post.id} post={post} />)
        )}
      </main>
    </div>
  );
}
