import { supabase } from "../supabase";
import "../pages/signin.css"; // importa o css
import googleIcon from "../assets/google-icon.png";
import appleIcon from "../assets/apple-icon.png";
import studentsImg from "../assets/students.png";

type SigninProps = {
  onLogin: (session: any) => void;
};

export default function Signin({ onLogin }: SigninProps) {
  const handleLogin = async (provider: "google" | "apple") => {
    // 1️⃣ Faz login com OAuth (Google ou Apple)
    const { error: loginError } = await supabase.auth.signInWithOAuth({ provider });
    if (loginError) {
      console.error("Erro no login OAuth:", loginError);
      return;
    }

    // 2️⃣ Obtem a sessão atual após o login
    const { data: sessionData, error: sessionError } = await supabase.auth.getSession();
    if (sessionError || !sessionData.session) {
      console.error("Erro ao obter sessão:", sessionError);
      return;
    }

    onLogin(sessionData.session);

    // 3️⃣ Obtem o usuário logado diretamente
    const { data: userData, error: userError } = await supabase.auth.getUser();
    if (userError || !userData.user) {
      console.error("Erro ao obter usuário logado:", userError);
      return;
    }

    const user = userData.user;

    // 4️⃣ Verificar e atualizar o profile com email
    if (user.email) {
      const { error: profileError } = await supabase
        .from("profiles")
        .upsert(
          [
            {
              id: user.id,                // mesmo id do usuário
              email: user.email ?? "",     // email obtido do login do Google
              created_at: new Date(),      // data de criação
            },
          ],
          {
            onConflict: "id",             // evita duplicar o perfil do usuário
          }
        );

      if (profileError) {
        console.error("Erro ao criar/atualizar profile:", profileError);
      } else {
        console.log("Profile atualizado com sucesso:", user.email);
      }
    } else {
      console.error("Email não encontrado após o login");
    }
  };

  return (
    <div className="signin-container">
      <div className="signin-card">
        <h1 className="signin-title">VibeU ✨</h1>
        <p className="signin-subtitle">
          Conecte-se com estudantes em Portugal!
        </p>

        {/* Botão Google */}
        <button
          onClick={() => handleLogin("google")}
          className="signin-btn google-btn"
        >
          <img src={googleIcon} alt="Google" className="signin-icon" />
          Entrar com Google
        </button>

        {/* Botão Apple */}
        <button
          onClick={() => handleLogin("apple")}
          className="signin-btn apple-btn"
        >
          <img src={appleIcon} alt="Apple" className="signin-icon" />
          Entrar com Apple
        </button>

        {/* Imagem abaixo */}
        <img src={studentsImg} alt="Students" className="students-img" />
      </div>
    </div>
  );
}
