import { useState } from "react";
import { supabase } from "../supabase";
// import { useNavigate } from "react-router-dom";  // REMOVIDO: não vamos navegar aqui
import "./onboardingwizard.css";

const universities = [
  "Universidade de Lisboa",
  "Universidade do Porto",
  "Universidade de Coimbra",
];
const courses = [
  "Engenharia Informática",
  "Medicina",
  "Direito",
  "Psicologia",
  "Arquitetura",
];

type Props = { onDone: () => void };

export default function OnboardingWizard({ onDone }: Props) {
  const [step, setStep] = useState(1);
  const [form, setForm] = useState({
    name: "",
    university: "",
    course: "",
    birthdate: "",
    photo: null as File | null,
    languages: [] as string[],
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  // const navigate = useNavigate();  // REMOVIDO

  const handleChange = (
    e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>
  ) => {
    const { name, value } = e.target;
    setForm((f) => ({ ...f, [name]: value }));
  };

  const handlePhoto = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files?.[0]) {
      setForm((f) => ({ ...f, photo: e.target.files![0] }));
    }
  };

  const toggleLanguage = (lang: string) => {
    setForm((prev) => {
      const already = prev.languages.includes(lang);
      if (already) {
        return { ...prev, languages: prev.languages.filter((l) => l !== lang) };
      }
      if (prev.languages.length >= 3) return prev; // máximo 3
      return { ...prev, languages: [...prev.languages, lang] };
    });
  };

  const validateStep = () => {
    setError(""); // limpa erro antes
    if (step === 1) {
      if (!form.name.trim()) return setError("O nome é obrigatório.");
      if (!form.birthdate) return setError("A data de nascimento é obrigatória.");
      if (form.languages.length < 1)
        return setError("Selecione pelo menos 1 idioma.");
    }
    if (step === 2) {
      if (!form.university) return setError("Selecione a universidade.");
      if (!form.course) return setError("Selecione o curso.");
    }
    if (step === 3) {
      if (!form.photo) return setError("Envie uma foto de perfil.");
    }
    return true;
  };

  const nextStep = () => {
    if (validateStep() === true) setStep(step + 1);
  };

  const prevStep = () => {
    setError("");
    setStep(step - 1);
  };

  const handleSubmit = async () => {
    if (validateStep() !== true) return;

    setLoading(true);
    const user = (await supabase.auth.getUser()).data.user;
    if (!user) return;

    let avatar_url = null;
    if (form.photo) {
      const fileExt = form.photo.name.split(".").pop();
      const filePath = `${user.id}.${fileExt}`;

      const { error: uploadError } = await supabase.storage
        .from("avatars")
        .upload(filePath, form.photo, { upsert: true });

      if (uploadError) {
        console.error(uploadError);
      } else {
        const { data } = supabase.storage.from("avatars").getPublicUrl(filePath);
        avatar_url = data.publicUrl;
      }
    }

    const { error } = await supabase.from("profiles").upsert({
      id: user.id,
      name: form.name,
      university: form.university,
      course: form.course,
      birthdate: form.birthdate,
      avatar_url,
      languages: form.languages,
    });

    setLoading(false);

    if (error) {
      console.error(error);
      alert(error.message);
    } else {
      // Em vez de navegar, sinaliza para o App concluir o onboarding
      onDone();
    }
  };

  const stepsTotal = 3;

  return (
    <div className="onboarding-container">
      <div className="onboarding-box">
        <h1 className="title">✨ VibeU</h1>
        <h2 className="subtitle">Complete seu perfil</h2>

        {/* Progress Bar */}
        <div className="progress-container">
          <div
            className="progress-bar"
            style={{ width: `${(step / stepsTotal) * 100}%` }}
          ></div>
        </div>
        <p className="step-counter">
          Passo {step} de {stepsTotal}
        </p>

        {error && <p className="error">{error}</p>}

        {/* STEP 1 */}
        {step === 1 && (
          <>
            <label>Qual o seu nome?</label>
            <input
              className="input"
              name="name"
              value={form.name}
              onChange={handleChange}
              placeholder="Seu nome"
            />

            <label>Data de nascimento</label>
            <input
              type="date"
              className="input"
              name="birthdate"
              value={form.birthdate}
              onChange={handleChange}
            />

            <label>Quantos idiomas você fala?</label>
            <div className="languages">
              {["Português", "Inglês", "Espanhol", "Francês"].map((lang) => (
                <span
                  key={lang}
                  className={`chip ${
                    form.languages.includes(lang) ? "selected" : ""
                  }`}
                  onClick={() => toggleLanguage(lang)}
                >
                  {lang}
                </span>
              ))}
            </div>

            <button className="btn-primary" onClick={nextStep}>
              Próximo
            </button>
          </>
        )}

        {/* STEP 2 */}
        {step === 2 && (
          <>
            <label>Universidade</label>
            <select
              className="input"
              name="university"
              value={form.university}
              onChange={handleChange}
            >
              <option value="">Selecione sua universidade</option>
              {universities.map((u, i) => (
                <option key={i} value={u}>
                  {u}
                </option>
              ))}
            </select>

            <label>Curso</label>
            <select
              className="input"
              name="course"
              value={form.course}
              onChange={handleChange}
            >
              <option value="">Selecione seu curso</option>
              {courses.map((c, i) => (
                <option key={i} value={c}>
                  {c}
                </option>
              ))}
            </select>

            <div className="nav-buttons">
              <button className="btn-secondary" onClick={prevStep}>
                Voltar
              </button>
              <button className="btn-primary" onClick={nextStep}>
                Próximo
              </button>
            </div>
          </>
        )}

        {/* STEP 3 */}
        {step === 3 && (
          <>
            <label>Upload da sua foto</label>
            <input
              type="file"
              accept="image/*"
              className="input"
              onChange={handlePhoto}
            />

            <div className="nav-buttons">
              <button className="btn-secondary" onClick={prevStep}>
                Voltar
              </button>
              <button
                className="btn-primary"
                onClick={handleSubmit}
                disabled={loading}
              >
                {loading ? "Salvando..." : "Concluir"}
              </button>
            </div>
          </>
        )}
      </div>
    </div>
  );
}
