import { useEffect, useState } from "react";
import Signin from "./pages/signin";
import OnboardingWizard from "./components/OnboardingWizard";
import { supabase } from "./supabase";
import Feed from "./pages/feed";   // 👈 importa aqui

export default function App() {
  const [session, setSession] = useState<any | null>(null);
  const [onboarded, setOnboarded] = useState<boolean | null>(null);
  const [loading, setLoading] = useState(true);

  // pega sessão inicial
  useEffect(() => {
    supabase.auth.getSession().then(({ data }) => {
      setSession(data.session);
      setLoading(false);
    });

    const { data: listener } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });

    return () => {
      listener.subscription.unsubscribe();
    };
  }, []);

  // checa se o usuário já fez onboarding
  useEffect(() => {
    const checkProfile = async () => {
      if (session) {
        const { data } = await supabase
          .from("profiles")
          .select("id")
          .eq("id", session.user.id)
          .single();
        setOnboarded(!!data);
      }
    };
    if (session) checkProfile();
  }, [session]);

  if (loading) return <p>Carregando...</p>;

  // 🚀 ordem correta
  if (!session) return <Signin onLogin={(s) => setSession(s)} />;
  if (onboarded === false) return <OnboardingWizard onDone={() => setOnboarded(true)} />;
  if (onboarded) return <Feed />;  // 👈 agora chama teu feed.tsx

  return null;
}
